344→val downloadWindowsZonesMapping by tasks.registering {
345→    description = "Updates the mapping between Windows-specific and usual names for timezones"
346→    val output = "$projectDir/windows/src/internal/WindowsZoneNames.kt"
347→    outputs.file(output)
348→    doLast {
349→        val initialFileContents = try { File(output).readBytes() } catch(e: Throwable) { ByteArray(0) }
350→        val documentBuilderFactory = DocumentBuilderFactory.newInstance()
351→        // otherwise, parsing fails since it can't find the dtd
352→        documentBuilderFactory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
353→        val builder = documentBuilderFactory.newDocumentBuilder()
354→        val url = URL("https://raw.githubusercontent.com/unicode-org/cldr/master/common/supplemental/windowsZones.xml")
355→        val xmlDoc = with(url.openConnection() as java.net.HttpURLConnection) {
356→            builder.parse(this.inputStream)
357→        }
358→        xmlDoc.documentElement.normalize()
359→        val mapZones = xmlDoc.getElementsByTagName("mapZone")
360→        val mapping = linkedMapOf<String, String>()
361→        mapping["UTC"] = "UTC"
362→        for (i in 0 until mapZones.length) {
363→            val mapZone = mapZones.item(i)
364→            val windowsName = mapZone.attributes.getNamedItem("other").nodeValue
365→            val usualNames = mapZone.attributes.getNamedItem("type").nodeValue
366→            for (usualName in usualNames.split(' ')) {
367→                if (usualName == "") continue
368→                val oldWindowsName = mapping[usualName] // don't do it in `put` to preserve the order in the map
369→                if (oldWindowsName == null) {
370→                    mapping[usualName] = windowsName
371→                } else if (oldWindowsName != windowsName) {
372→                    throw Error("Ambiguous mapping: '$usualName' to '$oldWindowsName' and '$windowsName'")
373→                }
374→            }
375→        }
376→        val sortedMapping = mapping.toSortedMap()
377→        val bos = ByteArrayOutputStream()
378→        PrintWriter(bos).use { out ->
379→            out.println("""// generated with gradle task `$name`""")
380→            out.println("""package kotlinx.datetime.internal""")
381→            out.println("""internal val standardToWindows: Map<String, String> = mutableMapOf(""")
382→            for ((usualName, windowsName) in sortedMapping) {
383→                out.println("  \"$usualName\" to \"$windowsName\",")
384→            }
385→            out.println(")")
386→            out.println("""internal val windowsToStandard: Map<String, String> = mutableMapOf(""")
387→            val reverseMap = sortedMapOf<String, String>()
388→            for ((usualName, windowsName) in mapping) {
389→                if (reverseMap[windowsName] == null) {
390→                    reverseMap[windowsName] = usualName
391→                }
392→            }
393→            for ((windowsName, usualName) in reverseMap) {
394→                out.println("  \"$windowsName\" to \"$usualName\",")
395→            }
396→            out.println(")")
397→        }
398→        val newFileContents = bos.toByteArray()
399→        if (!(initialFileContents contentEquals newFileContents)) {
400→            File(output).writeBytes(newFileContents)
401→            throw GradleException("The mappings between Windows and IANA timezone names changed. " +
402→                "The new mappings were written to the filesystem.")
403→        }
404→    }
405→}
