 *
 * ### Behavior and system-specifics
 *
 * [Clock.System] accesses the platform's system clock. Depending on the platform, the precision of the returned
 * [Instant] values may vary, but it is guaranteed to be at least millisecond precision.
 * The values returned are not guaranteed to be monotonically increasing: the system clock may be adjusted
 * at any time, for example, due to NTP synchronization.
 *
 * ### Usage example
 *
 * Getting the current date in a specific time zone:
 *
 * ```
 * val now: Instant = Clock.System.now()
 * val today: LocalDate = now.toLocalDateTime(TimeZone.currentSystemDefault()).date
 * // or equivalently:
 * val today2: LocalDate = Clock.System.todayIn(TimeZone.currentSystemDefault())
 * ```
 *
 * @see Clock.System for the system clock.
 * @see Clock.todayIn for getting the current date.
 */
public interface Clock {
    /**
     * Returns the [Instant] corresponding to the current time, according to this clock.
     */
    public fun now(): Instant

    /**
     * The [Clock] instance that queries the operating system as its source of knowledge of time.
     *
     * Successive calls to [now] will not necessarily return increasing [Instant] values, as the system clock
     * can be adjusted at any time.
     *
     * The time resolution depends on the platform: on some platforms, it can be as low as one millisecond.
     */
    public object System : Clock {
        override fun now(): Instant = @Suppress("DEPRECATION_ERROR") Instant.now()
    }

    public companion object {

    }
}

